export type LoyaltySettingsProgramType = typeof LoyaltySettingsProgramType[keyof typeof LoyaltySettingsProgramType];


export const LoyaltySettingsProgramType = {
  cashback: 'cashback',
  points: 'points',
  tiered: 'tiered',
  stamp: 'stamp',
  custom: 'custom',
} as const;

/**
 * How loyalty points expire.
 */
export type LoyaltySettingsExpiryMode = typeof LoyaltySettingsExpiryMode[keyof typeof LoyaltySettingsExpiryMode];


export const LoyaltySettingsExpiryMode = {
  none: 'none',
  daysSinceLastPurchase: 'daysSinceLastPurchase',
  fixedDays: 'fixedDays',
  endOfYear: 'endOfYear',
  fixedDate: 'fixedDate',
} as const;

export interface LoyaltyNaming {
  /** Shown on receipts and customer screens. Blank uses the default program type label. */
  programName?: string;
  cashbackUnit?: string;
  pointsUnit?: string;
  stampUnit?: string;
  tieredUnit?: string;
  customUnit?: string;
}

export interface LoyaltySettings {
  programType: LoyaltySettingsProgramType;
  isEnabled: boolean;
  cashbackRate?: number;
  pointsPerDollar?: number;
  dollarPerPoint?: number;
  tiers?: LoyaltyTier[];
  stampsRequired?: number;
  stampRewardValue?: number;
  customDescription?: string;
  customValue?: number;
  excludedCustomerGroups?: string[];
  /** How loyalty points expire. */
  expiryMode?: LoyaltySettingsExpiryMode;
  /**
     * Numeric value for the expiry mode (e.g. days count). Null when mode is 'none' or 'endOfYear'.
     * @nullable
     */
  expiryValue?: number | null;
  /** Active loyalty promotions (Double Points, Category Bonuses, etc.). */
  promotions?: LoyaltyPromotion[];
  /** Custom names for the program and its reward units. Synced across all staff devices. */
  naming?: LoyaltyNaming;
}

